#include <bits/stdc++.h>
using namespace std;

const int N=2010,M=4e4+10;

int n,m,a[N],b[N],f[N][M];

int main(){
    int c,T=1;
    while(T--){
        scanf("%d%d",&n,&m);
        for(int i=1;i<n;i++)
            scanf("%d%d",&a[i],&b[i]);
        memset(f,0xcf,sizeof(f));
        for(int j=0;j<m;j++)
            f[1][j]=j;
        for(int i=1;i<n;i++){
            int tmp=-1e9;
            for(int j=0;j<a[i];j++)
                tmp=max(tmp,f[i][j]);
            for(int j=0;j<=4e4;j++){
                if(j>=a[i]+b[i])
                    f[i+1][j]=max(f[i+1][j],f[i][j]);
                else if(j>=a[i])
                    f[i+1][j-a[i]]=max(f[i+1][j-a[i]],f[i][j]);
                else{
                    f[i+1][j+b[i]]=max(f[i+1][j+b[i]],f[i][j]+b[i]);
                    tmp=max(tmp,f[i][j]);
                }
            }
            for(int j=0;j<b[i];j++)
                f[i+1][j]=max(f[i+1][j],tmp+j);
        }
        int ans=-1e9;
        for(int i=0;i<=4e4;i++)
            ans=max(ans,f[n][i]);
        printf("%d\n",ans);
    }
    return 0;
}
